def unpack():
    print("Extracting folder natively...")
    raw_bytes = lzma.decompress(base64.b85decode(DATA.encode('utf-8')))
    with zipfile.ZipFile(io.BytesIO(raw_bytes), "r") as z:
        z.extractall(".")
    print("[SUCCESS] Restored perfectly!")

